script:
// Client script for the standard ERPNext Item doctype.
// Adds a "Print Barcode" button that sends ZPL to the Zebra ZD220 via QZ Tray.

var _QZ_SETTINGS_KEY = "qz_printer_settings";

function _loadPrinterSettings() {
  try {
    return JSON.parse(localStorage.getItem(_QZ_SETTINGS_KEY)) || {};
  } catch (e) {
    return {};
  }
}

function _savePrinterSettings(values) {
  try {
    localStorage.setItem(
      _QZ_SETTINGS_KEY,
      JSON.stringify({
        printer_name: values.printer_name || "",
        price_list: values.price_list || "",
        currency: values.currency || "",
        language: values.language || "",
      })
    );
  } catch (e) { }
}

function _showPrinterPicker(target_field) {
  frappe.show_alert({ message: __("Connecting to QZ Tray..."), indicator: "blue" });
  QZBarcodeUtils.listPrinters()
    .then(function (printers) {
      if (!Array.isArray(printers)) printers = [printers];
      if (!printers.length) {
        frappe.msgprint(__("No printers found via QZ Tray."));
        return;
      }
      var picker = new frappe.ui.Dialog({
        title: __("Select Printer"),
        fields: [
          {
            label: __("Printer"),
            fieldname: "chosen",
            fieldtype: "Select",
            options: printers.join("\n"),
            default: printers[0],
            reqd: 1,
          },
        ],
        primary_action_label: __("Select"),
        primary_action: function (vals) {
          target_field.set_value(vals.chosen);
          picker.hide();
        },
      });
      picker.show();
    })
    .catch(function (err) {
      frappe.msgprint({
        title: __("QZ Tray Error"),
        indicator: "red",
        message: err.message || __("Could not connect to QZ Tray. Make sure it is running."),
      });
    });
}

function _fetchItemPrice(item_code, price_list, dialog) {
  if (!price_list) return;
  frappe.call({
    method: "frappe.client.get_value",
    args: {
      doctype: "Item Price",
      filters: { item_code: item_code, price_list: price_list },
      fieldname: "price_list_rate",
    },
    callback: function (r) {
      var rate = r.message && r.message.price_list_rate;
      dialog.set_value("price", rate != null ? rate : "");
    },
  });
}

frappe.ui.form.on("Item", {
  refresh: function (frm) {
    frm.add_custom_button(__("Print Barcode"), function () {
      var item_code = frm.doc.name;

      if (!item_code || frm.is_new()) {
        frappe.msgprint(__("Please save the item before printing a barcode."));
        return;
      }

      var saved = _loadPrinterSettings();

      frappe.call({
        method: "frappe.client.get_list",
        args: {
          doctype: "Price List",
          filters: { enabled: 1 },
          fields: ["name", "currency"],
          order_by: "name asc",
          limit_page_length: 100,
        },
        callback: function (r) {
          var priceLists = r.message || [];
          var plOptions = priceLists.map(function (pl) { return pl.name; }).join("\n");
          var plCurrencyMap = {};
          priceLists.forEach(function (pl) { plCurrencyMap[pl.name] = pl.currency; });

          var defaultPL = saved.price_list || (priceLists.length ? priceLists[0].name : "");
          var allCurrencies = priceLists
            .map(function (pl) { return pl.currency; })
            .filter(function (c, i, a) { return c && a.indexOf(c) === i; })
            .sort();
          if (allCurrencies.indexOf("HUF") === -1) allCurrencies.unshift("HUF");
          var defaultCurrency = saved.currency || plCurrencyMap[defaultPL] || "HUF";

          // Default language — prefer Hungarian
          var defaultLang = saved.language || "hu";
          var languageOptions = "hu\nen\nde\nro\nfr\nit\nes";
          var translationsMap = {};

          var d = new frappe.ui.Dialog({
            title: __("Print Barcode Label"),
            fields: [
              {
                label: __("Item Code"),
                fieldname: "item_code",
                fieldtype: "Data",
                read_only: 1,
                default: item_code,
              },
              {
                label: __("Quantity"),
                fieldname: "qty",
                fieldtype: "Int",
                default: 1,
                reqd: 1,
              },
              { fieldtype: "Section Break", label: __("Price") },
              {
                label: __("Price List"),
                fieldname: "price_list",
                fieldtype: "Select",
                options: plOptions,
                default: defaultPL,
                onchange: function () {
                  var pl = d.get_value("price_list");
                  d.set_value("currency", plCurrencyMap[pl] || "HUF");
                  _fetchItemPrice(item_code, pl, d);
                },
              },
              {
                label: __("Currency"),
                fieldname: "currency",
                fieldtype: "Select",
                options: allCurrencies.join("\n"),
                default: defaultCurrency,
                reqd: 1,
              },
              {
                label: __("Price"),
                fieldname: "price",
                fieldtype: "Float",
                description: __("Auto-fetched from the selected price list."),
              },
              { fieldtype: "Section Break", label: __("Language") },
              {
                label: __("Label Language"),
                fieldname: "language",
                fieldtype: "Select",
                options: languageOptions,
                default: defaultLang,
                description: __("Item name will be translated to this language on the label."),
              },
              { fieldtype: "Section Break", label: __("Printer") },
              {
                label: __("Printer Name"),
                fieldname: "printer_name",
                fieldtype: "Data",
                default: saved.printer_name || "",
                description: __("Exact CUPS printer name. Leave blank to auto-detect Zebra."),
              },
              {
                label: __("Detect Available Printers"),
                fieldname: "detect_btn",
                fieldtype: "Button",
              },
            ],
            primary_action_label: __("Print"),
            primary_action: function (values) {
              if (!values.qty || values.qty < 1) {
                frappe.msgprint(__("Please enter a valid quantity (minimum 1)."));
                return;
              }
              _savePrinterSettings(values);
              d.hide();

              // Use translated item name if available, otherwise fallback
              var translatedName = translationsMap[values.language] || frm.doc.item_name || "";

              frappe.show_alert({
                message: __("Sending {0} label(s) to printer...", [values.qty]),
                indicator: "blue",
              });

              QZBarcodeUtils.printBarcodes(
                [{
                  item_code: item_code,
                  item_name: translatedName,
                  qty: values.qty,
                  price: values.price || null,
                  currency: values.currency || "HUF",
                  label_info: frm.doc.label_info || null,
                }],
                { printerName: values.printer_name },
                { [item_code]: translationsMap },
                values.language
              )
                .then(function () {
                  frappe.show_alert({
                    message: __("{0} label(s) sent to printer.", [values.qty]),
                    indicator: "green",
                  });
                })
                .catch(function (err) {
                  frappe.msgprint({
                    title: __("Print Error"),
                    indicator: "red",
                    message: err.message || __("Failed to print."),
                  });
                });
            },
          });

          d.get_field("detect_btn").$input.on("click", function () {
            _showPrinterPicker(d.get_field("printer_name"));
          });

          d.show();

          // Fetch translations for the default language
          frappe.call({
            method: "scripts.api.get_item_translations",
            args: { item_code: item_code, languages: "hu,en,de,ro,fr,it,es" },
            callback: function (r) {
              translationsMap = r.message || {};
              // Auto-display translated name if the default language has one
              var initialLang = d.get_value("language");
              if (translationsMap[initialLang] && translationsMap[initialLang] !== frm.doc.item_name) {
                // Optionally show the translated name — currently we just store it
              }
            },
          });

          if (defaultPL) {
            _fetchItemPrice(item_code, defaultPL, d);
          }
        },
      });
    });
  },
});

frappe.ui.form.on('BOM', {
  setup: function (frm) {
    frm.set_query("main_fabric", function () {
      return {
        filters: [["Item", "item_group", "descendants of", "Anyagok"]]
      };
    });
  }
});

// Load ERPNext's SellingController (defines item_code auto-fill, UOM, pricing, etc.)
erpnext.sales_common.setup_selling_controller();

frappe.ui.form.on('Sales Order', {
  refresh: function (frm) {
    if (frm.doc.docstatus === 1) {
      frm.add_custom_button(__('Generate Work Orders'), function () {
        frappe.call({
          method: "scripts.api.generate_work_orders",
          args: {
            sales_order: frm.doc.name
          },
          freeze: true,
          callback: function (r) {
            // Success message is handled by python side
          }
        });
      });

      if (frm.doc.project) {
        frm.add_custom_button(__('Duplicate Sales Order'), function () {
          frappe.prompt([
            {
              label: 'Number of Copies',
              fieldname: 'count',
              fieldtype: 'Int',
              reqd: 1,
              default: 1,
              description: "How many times do you want to duplicate this Sales Order?"
            }
          ], (values) => {
            if (values.count > 0) {
              frappe.call({
                method: "scripts.api.duplicate_sales_orders",
                args: {
                  source_name: frm.doc.name,
                  count: values.count
                },
                freeze: true,
                callback: function (r) {
                  if (r.message) {
                    frappe.msgprint(r.message);
                  }
                }
              });
            }
          }, __('Duplicate Sales Order'), __('Duplicate'));
        });
      }
    }
  },
  setup: function (frm) {
    frm.set_query("fabric", "items", function () {
      return {
        query: "scripts.api.get_fabric_items"
      };
    });
  },

  // Propagate the parent delivery_date to any items that don't have one set
  delivery_date: function (frm) {
    $.each(frm.doc.items || [], function (i, d) {
      if (!d.delivery_date) d.delivery_date = frm.doc.delivery_date;
    });
    refresh_field("items");
  },
});

// Wire up ERPNext's SellingController so it handles item_code auto-fill
// (item_name, UOM, conversion_factor, pricing) for this form
extend_cscript(cur_frm.cscript, new erpnext.selling.SellingController({ frm: cur_frm }));

frappe.ui.form.on('Sales Order Item', {
  item_code: function (frm, cdt, cdn) {
    var row = locals[cdt][cdn];
    if (!row.item_code) return;

    // Set delivery_date from parent (mirrors ERPNext Sales Order behaviour)
    if (frm.doc.delivery_date) {
      row.delivery_date = frm.doc.delivery_date;
      refresh_field("delivery_date", cdn, "items");
    } else {
      frm.script_manager.copy_from_first_row("items", row, ["delivery_date"]);
    }

    // item_name / UOM / conversion_factor are filled by SellingController
    // (TransactionController.item_code → get_item_details)

    // Fabric/BOM lookup for Products group items
    frappe.db.get_value("Item", row.item_code, "item_group", function (r) {
      if (!r || r.item_group !== "Products") return;
      if (row.fabric) {
        lookup_bom_for_fabric(frm, cdt, cdn, row.item_code, row.fabric);
      }
    });
  },

  // When a row's delivery_date changes, propagate to all rows if no parent date
  delivery_date: function (frm, cdt, cdn) {
    if (!frm.doc.delivery_date) {
      erpnext.utils.copy_value_in_all_rows(frm.doc, cdt, cdn, "items", "delivery_date");
    }
  },


  fabric: function (frm, cdt, cdn) {
    var row = locals[cdt][cdn];
    if (!row.item_code || !row.fabric) return;

    frappe.db.get_value("Item", row.item_code, "item_group", function (r) {
      if (!r || r.item_group !== "Products") return;
      lookup_bom_for_fabric(frm, cdt, cdn, row.item_code, row.fabric);
    });
  },

  // When Fazon (style) is selected, auto-fill related data
  custom_fazon: function (frm, cdt, cdn) {
    var row = locals[cdt][cdn];
    if (!row.custom_fazon) return;

    // Fetch Fazon details and auto-fill related fields
    frappe.db.get_value("Fazon", row.custom_fazon, [
      "custom_anyag", "custom_kidolgozasok", "custom_merettabla"
    ], function (r) {
      if (!r) return;
      var changed = false;

      if (r.custom_anyag && row.custom_anyag !== r.custom_anyag) {
        frappe.model.set_value(cdt, cdn, "custom_anyag", r.custom_anyag);
        changed = true;
      }
      if (r.custom_kidolgozasok && row.custom_kidolgozasok !== r.custom_kidolgozasok) {
        frappe.model.set_value(cdt, cdn, "custom_kidolgozasok", r.custom_kidolgozasok);
        changed = true;
      }
      if (r.custom_merettabla && row.custom_merettabla !== r.custom_merettabla) {
        frappe.model.set_value(cdt, cdn, "custom_merettabla", r.custom_merettabla);
        changed = true;
      }
    });
  },

  // When Szett / Csomag changes, offer to copy to other rows with same item_code
  custom_szett: function (frm, cdt, cdn) {
    var row = locals[cdt][cdn];
    if (!row.custom_szett || !row.item_code) return;

    // Optionally auto-fill szett for rows with same item_code
    frm.doc.items.forEach(function (item) {
      if (item.name !== cdn && item.item_code === row.item_code && !item.custom_szett) {
        frappe.model.set_value(item.doctype, item.name, "custom_szett", row.custom_szett);
      }
    });
    refresh_field("items");
  }
});

function lookup_bom_for_fabric(frm, cdt, cdn, item_code, fabric) {
  frappe.db.get_value(
    "BOM",
    {
      "item": item_code,
      "main_fabric": fabric,
      "is_active": 1,
      "docstatus": 1
    },
    "kidolgozasok",
    function (r) {
      if (r && r.kidolgozasok) {
        var row = locals[cdt][cdn];
        if (row.finishing !== r.kidolgozasok) {
          frappe.model.set_value(cdt, cdn, "finishing", r.kidolgozasok);
        }
      }
    }
  );
}

frappe.ui.form.on('Project', {
  refresh: function (frm) {
    if (!frm.is_new()) {
      frm.add_custom_button(__('Generate Work Orders for Sales Orders'), function () {
        frappe.confirm(
          __('Are you sure you want to generate Work Orders for all submitted Sales Orders linked to this Project?'),
          function () {
            frappe.call({
              method: 'scripts.api.generate_work_orders_from_project',
              args: {
                project: frm.doc.name
              },
              freeze: true,
              callback: function (r) {
                // Message handled in python
              }
            });
          }
        );
      });
    }
  }
});

frappe.ui.form.on("Work Order", {
  refresh(frm) {
    // Define has_reservation at the top level of the function
    let has_reservation = frm.doc.custom_reservation_log && frm.doc.custom_reservation_log.length > 0;

    // MOST MÁR Draft (0) és Submitted (1) állapotban is engedjük
    // De Cancelled (2)-ben nem.
    if (frm.doc.docstatus < 2 && frm.doc.status !== "Completed") {

      // Gomb felirat és szín logika
      let label = '';
      let btn_class = '';

      if (has_reservation) {
        // Ha van foglalás, de a WO Draft, akkor ez "Frissítés" lesz
        if (frm.doc.docstatus === 0) {
          label = __('Foglalás Frissítése'); // Revert + New Reserve
          btn_class = 'btn-warning'; // Narancs szín a figyelemfelkeltéshez
        } else {
          // Ha Submitted és van foglalás, akkor inkább Visszavonást kínálunk fel
          label = __('Foglalás Visszavonása');
          btn_class = 'btn-danger';
        }
      } else {
        label = __('Anyagok Lefoglalása');
        btn_class = 'btn-primary';
      }

      // GOMB HOZZÁADÁSA
      frm.add_custom_button(label, function () {

        // Ha Visszavonás (Csak Submitted állapotban, meglévő foglalásnál)
        if (has_reservation && frm.doc.docstatus === 1) {
          frappe.confirm('Biztosan vissza akarja mozgatni az anyagokat?', function () {
            call_api('scripts.api.cancel_physical_reservation', { wo_name: frm.doc.name });
          });
        }
        // Ha Foglalás vagy Frissítés (Draft vagy Üres Submitted)
        else {
          let fields = [
            {
              label: 'Cél Raktár',
              fieldname: 'target_warehouse',
              fieldtype: 'Link',
              options: 'Warehouse',
              reqd: 1
            }
          ];

          if (has_reservation) {
            fields.push({
              label: 'Előző foglalás törlése (Teljes újragenerálás)',
              fieldname: 'reset_reservation',
              fieldtype: 'Check',
              default: 0,
              description: 'Ha be van pipálva, a rendszer visszavonja a jelenlegi foglalást és újra lefoglal mindent. Ha nincs, csak a hiányzó tételeket foglalja le.'
            });
          }

          let d = new frappe.ui.Dialog({
            title: has_reservation ? 'Foglalás Frissítése' : 'Fizikai Foglalás',
            fields: fields,
            primary_action_label: has_reservation ? 'Frissítés' : 'Lefoglalás',
            primary_action: function (values) {
              d.hide();

              let method = 'scripts.api.create_physical_reservation';
              // Ha van foglalás ÉS NEM kértük a resetet, akkor update (additive)
              if (has_reservation && !values.reset_reservation) {
                method = 'scripts.api.update_physical_reservation';
              }

              call_api(method, {
                wo_name: frm.doc.name,
                target_warehouse: values.target_warehouse
              });
            }
          });

          d.fields_dict.target_warehouse.get_query = function () {
            return {
              filters: {
                'is_group': 0
              }
            };
          };

          d.show();
        }

      }).addClass(btn_class);
    }


    let label = "Foglalas torlese"
    let btn_class = "btn-primary"

    let btn = frm.add_custom_button(label, function () {
      frappe.confirm("Biztonsan torolni akarod a foglalast?", () => {
        call_api("scripts.api.cancel_physical_reservation", { wo_name: frm.doc.name })
      })
    })

    if (!has_reservation) {
      btn.prop('disabled', true)
    } else {
      btn.addClass(btn_class)
    }

    frm.add_custom_button(__('Copy Finishing Details'), function () {
      frappe.call({
        method: "scripts.api.get_related_work_orders",
        args: { wo_name: frm.doc.name },
        freeze: true,
        callback: function (r) {
          if (!r.message || r.message.length === 0) {
            frappe.msgprint(__("No other Work Orders found for this Item and Sales Order."));
            return;
          }

          let work_orders = r.message;

          let d = new frappe.ui.Dialog({
            title: __('Select Work Orders'),
            fields: [
              {
                fieldtype: 'HTML',
                fieldname: 'wo_list'
              }
            ],
            primary_action_label: __('Copy to Selected'),
            primary_action: function () {
              let selected_wos = [];
              d.$wrapper.find('.wo-checkbox:checked').each(function () {
                selected_wos.push($(this).val());
              });

              if (selected_wos.length === 0) {
                frappe.msgprint(__("Please select at least one Work Order."));
                return;
              }

              frappe.confirm(__("Copy finishing details to {0} Work Orders? This will overwrite existing details.", [selected_wos.length]), () => {
                call_copy_api(selected_wos);
                d.hide();
              });
            }
          });

          let html = `
						<style>
							.wo-select-table th, .wo-select-table td { padding: 8px; }
							.wo-select-table { width: 100%; border-collapse: collapse; }
							.wo-select-table thead { background-color: var(--control-bg); font-weight: bold; }
						</style>
						<div style="max-height: 400px; overflow-y: auto;">
							<table class="wo-select-table table table-bordered table-hover">
								<thead>
									<tr>
										<th style="width: 30px; text-align: center;"><input type="checkbox" id="select-all-wos"></th>
										<th>${__("Work Order")}</th>
										<th>${__("Status")}</th>
										<th>${__("Qty")}</th>
									</tr>
								</thead>
								<tbody>
					`;

          work_orders.forEach(wo => {
            html += `
							<tr>
								<td style="text-align: center;"><input type="checkbox" class="wo-checkbox" value="${wo.name}"></td>
								<td><a href="/app/work-order/${wo.name}" target="_blank">${wo.name}</a></td>
								<td>${wo.status}</td>
								<td>${wo.qty}</td>
							</tr>
						`;
          });

          html += `</tbody></table></div>`;

          d.fields_dict.wo_list.$wrapper.html(html);

          d.$wrapper.on('change', '#select-all-wos', function () {
            let checked = $(this).prop('checked');
            d.$wrapper.find('.wo-checkbox').prop('checked', checked);
          });

          d.add_custom_action(__('Copy to All'), () => {
            frappe.confirm(__("Copy finishing details to ALL {0} related Work Orders? This will overwrite existing details.", [work_orders.length]), () => {
              call_copy_api(null);
              d.hide();
            });
          });

          d.show();

          function call_copy_api(targets) {
            frappe.call({
              method: "scripts.api.copy_finishing_details",
              args: {
                wo_name: frm.doc.name,
                targets: targets
              },
              freeze: true,
              callback: function (r) {
                // Message handled in python
              }
            });
          }
        }
      });
    });

  }
});

// Segédfüggvény a híváshoz
function call_api(method, args) {
  frappe.call({
    method: method,
    args: args,
    freeze: true,
    freeze_message: "Készlet művelet folyamatban...",
    callback: function (r) {
      if (r.message && r.message.status === "success") {
        frappe.msgprint(r.message.message);
        cur_frm.reload_doc();
      } else {
        frappe.msgprint({
          title: 'Hiba / Info',
          message: r.message ? r.message.message : "Hiba történt",
          indicator: r.message && r.message.status === "info" ? "orange" : "red"
        });
      }
    }
  });
}
